const TODOS_LOS_PRODUCTOS = TODOS_LOS_PRODUCTOS_RAW.map(p => ({
  ...p,
  imagen_url: p.imagen ? `${STORAGE_BASE}/${p.imagen}` : null,
}));

export async function seedProductos() {
  console.log(`Seeding ${TODOS_LOS_PRODUCTOS.length} productos...`);

  const batchSize = 50;
  for (let i = 0; i < TODOS_LOS_PRODUCTOS.length; i += batchSize) {
    const batch = TODOS_LOS_PRODUCTOS.slice(i, i + batchSize);
    const { error } = await supabase
      .from('productos' as any)
      .upsert(batch as any, { onConflict: 'id' });

    if (error) {
      console.error(`Batch ${i}-${i + batchSize} error:`, error);
    } else {
      console.log(`✅ Batch ${i}-${i + batchSize} OK`);
    }
  }
  console.log('✅ Seed completo');
}
